{"code":"import json
import pandas as pd
import re

data_path = var_call_DOJ8NTBO8k3pUFTiKas6Zehx
with open(data_path, 'r', encoding='utf-8') as f:
    records = json.load(f)

def clean_date(s):
    if not s or not isinstance(s, str):
        return None
    s2 = s
    s2 = s2.replace('on ', ' ')
