    s2 = re.sub('(\d+)(st|nd|rd|th)', '\\1', s2)
    s2 = s2.replace(',', ' ')
    s2 = s2.strip()
    return pd.to_datetime(s2, dayfirst=True, errors='coerce')

filtered = []
for r in records:
