    if not (pd.Timestamp('2019-07-01') <= gd <= pd.Timestamp('2019-12-31')):
        continue
    pi = r.get('Patents_info','')
    pi_up = pi.upper()
    is_germany = False
    if 'GERMANY' in pi_up:
        is_germany = True
    else:
        if 'DE-' in pi_up or ' DE ' in pi_up or pi_up.startswith('DE'):
            is_germany = True
    if not is_germany:
        continue
    cpc_field = r.get('cpc')
    try:
        cpc_list = json.loads(cpc_field)
    except Exception:
