{"code":"import json, re
import pandas as pd

pubs_path = var_call_6s1Hx5RlvxTCOOHk3gPsx0tp
with open(pubs_path, 'r', encoding='utf-8') as f:
    records = json.load(f)

cpc_defs_path = var_call_A9wpvoxhstAfCpfAVll0D2La
with open(cpc_defs_path, 'r', encoding='utf-8') as f:
    cpc_defs = json.load(f)

cpc_level4 = set(d['symbol'] for d in cpc_defs if 'symbol' in d)
cpc_map = {d['symbol']: d.get('titleFull','') for d in cpc_defs}

def clean_date(s):
    if not s or not isinstance(s, str):
        return None
    s2 = s
    s2 = s2.replace('on ', ' ')
    s2 = s2.replace('dated ', ' ')
    s2 = s2.replace('the ', ' ')
    s2 = re.sub(r"(\d+)(st|nd|rd|th)", r"\1", s2)
    s2 = s2.replace(',', ' ')
    s2 = s2.strip()
    return pd.to_datetime(s2, dayfirst=True, errors='coerce')

def is_germany(pi):
    if not pi: return False
    s = pi.upper()
    if 'GERMANY' in s: return True
    if re.search(r'\bDE\b', s): return True
    if re.search(r'DE[-_]\d', s): return True
    if re.search(r'IN DE,', s): return True
    return False

rows = []
for r in records:
    gd = clean_date(r.get('grant_date'))
    if gd is None:
        continue
    if not (pd.Timestamp('2019-07-01') <= gd <= pd.Timestamp('2019-12-31')):
        continue
    if not is_germany(r.get('Patents_info','')):
        continue
    cpc_field = r.get('cpc')
    codes = []
    # try parse as json
    if isinstance(cpc_field, str):
        try:
            parsed = json.loads(cpc_field)
            if isinstance(parsed, list):
                for item in parsed:
                    if isinstance(item, dict):
                        code = item.get('code')
                        if code:
                            codes.append(code)
        except Exception:
            # fallback: regex find codes like Letter + 2 digits + optional letter + maybe slash and rest
            found = re.findall(r'[A-Z]\d{2}[A-Z]?\/?\d*', cpc_field)
            for f in found:
                codes.append(f)
    elif isinstance(cpc_field, list):
        for item in cpc_field:
            if isinstance(item, dict):
                code = item.get('code')
                if code:
                    codes.append(code)
    # parse filing date
    fd = clean_date(r.get('filing_date'))
    if fd is None:
        continue
    filing_year = int(fd.year)
    for code in codes:
        code = str(code).strip()
        # extract level4 group as first 3 chars (Letter+2digits)
        m = re.match(r'^([A-Z]\d{2})', code)
        if m:
            group = m.group(1)
        else:
            continue
        rows.append({'group': group, 'filing_year': filing_year})

if not rows:
    out = {'results': []}
    print('__RESULT__:')
    print(json.dumps(out))
else:
    df = pd.DataFrame(rows)
    counts = df.groupby(['group','filing_year']).size().reset_index(name='count')
    results = []
    for group, grp in counts.groupby('group'):
        # only include if level4 definition exists
        if group not in cpc_level4:
            continue
        grp_sorted = grp.sort_values('filing_year')
        s = pd.Series(grp_sorted['count'].values, index=grp_sorted['filing_year'].values)
        ema = s.ewm(alpha=0.1, adjust=False).mean()
        best_year = int(ema.idxmax())
        best_ema = float(ema.max())
        results.append({'symbol': group, 'titleFull': cpc_map.get(group,''), 'best_year': best_year, 'best_ema': best_ema})
    results = sorted(results, key=lambda x: x['best_ema'], reverse=True)
    print('__RESULT__:')
    print(json.dumps({'results': results}, ensure_ascii=False))"}
